import{_ as e,o as n,c as s,a2 as t}from"./chunks/framework.tNPPebLH.js";const b=JSON.parse('{"title":"跨平台构建与分发","description":"","frontmatter":{},"headers":[],"relativePath":"CROSS_PLATFORM.md","filePath":"CROSS_PLATFORM.md","lastUpdated":1783841449000}'),l={name:"CROSS_PLATFORM.md"};function i(d,a,o,r,p,c){return n(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="跨平台构建与分发" tabindex="-1">跨平台构建与分发 <a class="header-anchor" href="#跨平台构建与分发" aria-label="Permalink to &quot;跨平台构建与分发&quot;">​</a></h1><h2 id="平台边界" tabindex="-1">平台边界 <a class="header-anchor" href="#平台边界" aria-label="Permalink to &quot;平台边界&quot;">​</a></h2><p>Windows、macOS 和 Linux 桌面应用需要各自的原生工具链。Windows 本机不能可靠生成和签名 macOS DMG，普通 Linux 容器也不能替代 macOS 原生构建环境。</p><p>PetPack 提供两种可验证的跨平台路径：目标设备轻量构建，或 GitHub Actions 原生 runner 构建。</p><h2 id="当前平台成品和跨平台构建包" tabindex="-1">当前平台成品和跨平台构建包 <a class="header-anchor" href="#当前平台成品和跨平台构建包" aria-label="Permalink to &quot;当前平台成品和跨平台构建包&quot;">​</a></h2><table tabindex="0"><thead><tr><th>发布方式</th><th>产物</th><th>适用场景</th></tr></thead><tbody><tr><td>当前平台成品</td><td>当前系统运行程序、<code>petpack.bundle</code>、说明和 ZIP</td><td>当前设备使用，或分发给相同平台和架构的用户</td></tr><tr><td>跨平台构建包</td><td>宠物资源、构建请求、轻量 builder 和目标设备脚本</td><td>分发到不同操作系统，在目标设备生成原生桌宠</td></tr></tbody></table><h2 id="目标设备构建流程" tabindex="-1">目标设备构建流程 <a class="header-anchor" href="#目标设备构建流程" aria-label="Permalink to &quot;目标设备构建流程&quot;">​</a></h2><ol><li>在 Studio 导入并验证宠物。</li><li>在“发布桌宠”区域选择“导出跨平台构建包”。</li><li>将生成的 ZIP 分发到目标设备。</li><li>解压后双击 <code>START-HERE.html</code>，按接收设备选择一键入口： <ul><li>Windows：双击 <code>BUILD-WINDOWS.cmd</code>；</li><li>macOS：右键 <code>BUILD-MAC.command</code> 并选择“打开”；</li><li>Linux：运行 <code>BUILD-LINUX.sh</code>。</li></ul></li><li>在 <code>output/</code> 获取原生桌宠目录和 ZIP。</li></ol><p>构建包结构：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>petpack-cross-platform/</span></span>
<span class="line"><span>├── petpack.bundle/</span></span>
<span class="line"><span>├── build-request.json</span></span>
<span class="line"><span>├── builders/</span></span>
<span class="line"><span>├── START-HERE.html</span></span>
<span class="line"><span>├── BUILD-WINDOWS.cmd</span></span>
<span class="line"><span>├── BUILD-MAC.command</span></span>
<span class="line"><span>├── BUILD-LINUX.sh</span></span>
<span class="line"><span>├── build-here.ps1</span></span>
<span class="line"><span>├── build-here.sh</span></span>
<span class="line"><span>└── README.md</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>接收端不需要完整 Studio，也不需要 Codex。一键入口会检查构建器；若接力包未携带对应版本，首次运行会从固定的 PetPack Builder Release 自动下载，随后执行构建并打开 <code>output/</code>。失败时终端窗口会保留明确错误，不会一闪而过。</p><p>首次自动下载需要能访问 GitHub Release。下载失败时，<code>START-HERE.html</code> 会给出构建器发布页，可手动下载并解压到 <code>builders/</code>。Windows 可执行文件仍不能直接生成 macOS <code>.app</code>；macOS 构建器会按 Apple Silicon 或 Intel 自动选择。</p><h2 id="github-actions-原生构建" tabindex="-1">GitHub Actions 原生构建 <a class="header-anchor" href="#github-actions-原生构建" aria-label="Permalink to &quot;GitHub Actions 原生构建&quot;">​</a></h2><p>仓库包含三套工作流：</p><table tabindex="0"><thead><tr><th>工作流</th><th>用途</th></tr></thead><tbody><tr><td><code>build.yml</code></td><td>构建 Studio 的 Windows NSIS、macOS DMG、Linux AppImage/DEB</td></tr><tr><td><code>build-builders.yml</code></td><td>构建 Windows、macOS、Linux 轻量 builder</td></tr><tr><td><code>build-pet.yml</code></td><td>从可下载的跨平台构建包生成各平台桌宠</td></tr></tbody></table><p>运行 <code>build-pet.yml</code> 时填写 <code>source_url</code>。工作流会下载、检查并解压构建包，然后在原生 runner 上调用对应 builder。</p><h2 id="studio-release-产物" tabindex="-1">Studio Release 产物 <a class="header-anchor" href="#studio-release-产物" aria-label="Permalink to &quot;Studio Release 产物&quot;">​</a></h2><p>正式 Release 建议包含：</p><ul><li>Windows x64 NSIS；</li><li>macOS Apple Silicon DMG；</li><li>macOS Intel DMG；</li><li>Linux x64 AppImage；</li><li>Debian/Ubuntu x64 DEB；</li><li><code>SHA256SUMS.txt</code>；</li><li>简短更新说明和未签名提示。</li></ul><h2 id="代码签名" tabindex="-1">代码签名 <a class="header-anchor" href="#代码签名" aria-label="Permalink to &quot;代码签名&quot;">​</a></h2><p>未配置证书时，CI 只能生成未商业签名的社区构建：</p><ul><li>Windows 正式公开分发建议使用 Authenticode 代码签名；</li><li>macOS 建议使用 Developer ID、Hardened Runtime、公证和 stapling；</li><li>Linux 可根据发行版补充仓库签名或包签名。</li></ul><p>未签名包的首次启动方法见<a href="./troubleshooting">常见问题与排错</a>。</p><h2 id="docker-的作用" tabindex="-1">Docker 的作用 <a class="header-anchor" href="#docker-的作用" aria-label="Permalink to &quot;Docker 的作用&quot;">​</a></h2><p>Docker Web Studio 提供与桌面版一致的导入、校验、逐行动画预览和接力包导出流程，但不显示“构建当前 Linux 平台”。容器中可以挂载由原生 runner 预构建的 builder；容器 Linux 不被视为用户的目标设备，也不负责生成或签名 macOS 原生应用。详见 <a href="./DOCKER">Docker Web 版</a>。</p>`,25)])])}const h=e(l,[["render",i]]);export{b as __pageData,h as default};
